+// truncateID safely truncates an ID string to maxLen characters.
+// Returns the full string if it's shorter than maxLen.
+func truncateID(id string, maxLen int) string {
+	if len(id) <= maxLen {
+		return id
+	}
+	return id[:maxLen]
+}
